class Solution: def validateStackSequences(self, pushed: list[int], popped: list[int]) -> bool: len_pushed = len(pushed); stack = []; i = 0; j = len_pushed - 1; while i <= j: if pushed[i] == -1: while stack and stack[-1] != popped[j]: stack.pop(); stack.pop(); j -= 1; else: stack.append(pushed[i]); i += 1; return not stack;

if __name__ == '__main__':
    import sys
    input = sys.stdin.readline
    t = int(input())
    for _ in range(t):
        pushed = list(map(int, input().split()))
        popped = list(map(int, input().split()))
        solution = Solution()
        print(solution.validateStackSequences(pushed, popped))

