class Solution { public: bool validateStackSequences(vector<int>& pushed, vector<int>& popped) { int len = pushed.size(); stack<int> st; int i = 0, j = len - 1; while (i <= j) { if (pushed[i] == -1) { while (!st.empty() && st.top() != popped[j]) st.pop(); if (st.empty() || st.top() != popped[j]) j--; else st.pop(); } else { st.push(pushed[i]); i++; } } return st.empty(); } }; 

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);
    int t;
    cin >> t;
    while (t--) {
        int n;
        cin >> n;
        vector<int> pushed(n), popped(n);
        for (int i = 0; i < n; i++)
            cin >> pushed[i];
        for (int i = 0; i < n; i++)
            cin >> popped[i];
        Solution solution;
        cout << (solution.validateStackSequences(pushed, popped) ? "Yes" : "No") << \n;}
    return 0;
}
